import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useTheme } from '../App';
import { useCart } from '../context/CartContext';

const Cart = () => {
  const { isDark } = useTheme();
  const { cartItems, cartTotal, removeFromCart, updateQuantity, clearCart, checkout } = useCart();
  const [isCheckingOut, setIsCheckingOut] = useState(false);
  const navigate = useNavigate();

  const handleCheckout = () => {
    setIsCheckingOut(true);
    setTimeout(() => {
      const order = checkout();
      setIsCheckingOut(false);
      navigate('/orders');
    }, 1500);
  };

  if (cartItems.length === 0) {
    return (
      <div className="min-h-screen pt-24 pb-16">
        <div className="container-custom">
          <div className="text-center py-16">
            <div className="w-24 h-24 bg-gray-200 dark:bg-dark-300 rounded-full flex items-center justify-center mx-auto mb-6">
              <svg className={`w-12 h-12 ${isDark ? 'text-gray-500' : 'text-gray-400'}`} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 3h2l.4 2M7 13h10l4-8H5.4M7 13L5.4 5M7 13l-2.293 2.293c-.63.63-.184 1.707.707 1.707H17m0 0a2 2 0 100 4 2 2 0 000-4zm-8 2a2 2 0 11-4 0 2 2 0 014 0z" />
              </svg>
            </div>
            <h2 className={`text-2xl font-bold mb-4 ${isDark ? 'text-white' : 'text-gray-900'}`}>
              Your cart is empty
            </h2>
            <p className={`mb-8 ${isDark ? 'text-gray-400' : 'text-gray-600'}`}>
              Looks like you haven't added any items to your cart yet.
            </p>
            <Link to="/menu" className="btn-primary inline-block">
              Browse Menu
            </Link>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen pt-24 pb-16">
      <div className="container-custom">
        {/* Page Header */}
        <div className="mb-8">
          <h1 className={`text-3xl md:text-4xl font-display font-bold ${isDark ? 'text-white' : 'text-gray-900'}`}>
            Shopping <span className="text-primary-500">Cart</span>
          </h1>
          <p className={`mt-2 ${isDark ? 'text-gray-400' : 'text-gray-600'}`}>
            {cartItems.length} {cartItems.length === 1 ? 'item' : 'items'} in your cart
          </p>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          {/* Cart Items */}
          <div className="lg:col-span-2 space-y-4">
            {cartItems.map((item, index) => (
              <div
                key={item.id}
                className={`flex items-center gap-4 p-4 rounded-2xl transition-all duration-300 ${
                  isDark ? 'bg-dark-300 hover:bg-dark-400' : 'bg-white hover:shadow-lg'
                }`}
                style={{
                  animation: 'fadeIn 0.5s ease-out forwards',
                  animationDelay: `${index * 100}ms`,
                  opacity: 0,
                }}
              >
                {/* Image */}
                <div className="w-24 h-24 rounded-xl overflow-hidden flex-shrink-0">
                  <img
                    src={item.image}
                    alt={item.name}
                    className="w-full h-full object-cover"
                  />
                </div>

                {/* Details */}
                <div className="flex-grow">
                  <h3 className={`font-bold ${isDark ? 'text-white' : 'text-gray-900'}`}>
                    {item.name}
                  </h3>
                  <p className={`text-sm ${isDark ? 'text-gray-400' : 'text-gray-600'}`}>
                    {item.category}
                  </p>
                  <p className="text-primary-500 font-bold mt-1">
                    ${item.price.toFixed(2)}
                  </p>
                </div>

                {/* Quantity Controls */}
                <div className="flex items-center gap-3">
                  <button
                    onClick={() => updateQuantity(item.id, item.quantity - 1)}
                    className={`w-8 h-8 rounded-full flex items-center justify-center transition-colors ${
                      isDark ? 'bg-dark-400 hover:bg-dark-500' : 'bg-gray-100 hover:bg-gray-200'
                    }`}
                  >
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M20 12H4" />
                    </svg>
                  </button>
                  <span className={`font-bold w-8 text-center ${isDark ? 'text-white' : 'text-gray-900'}`}>
                    {item.quantity}
                  </span>
                  <button
                    onClick={() => updateQuantity(item.id, item.quantity + 1)}
                    className={`w-8 h-8 rounded-full flex items-center justify-center transition-colors ${
                      isDark ? 'bg-dark-400 hover:bg-dark-500' : 'bg-gray-100 hover:bg-gray-200'
                    }`}
                  >
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6v6m0 0v6m0-6h6m-6 0H6" />
                    </svg>
                  </button>
                </div>

                {/* Remove Button */}
                <button
                  onClick={() => removeFromCart(item.id)}
                  className={`p-2 rounded-full transition-colors ${
                    isDark ? 'hover:bg-red-500/20 text-gray-400 hover:text-red-500' : 'hover:bg-red-100 text-gray-400 hover:text-red-500'
                  }`}
                >
                  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                  </svg>
                </button>

                {/* Item Total */}
                <div className="text-right">
                  <p className={`font-bold text-lg ${isDark ? 'text-white' : 'text-gray-900'}`}>
                    ${(item.price * item.quantity).toFixed(2)}
                  </p>
                </div>
              </div>
            ))}

            {/* Clear Cart */}
            <button
              onClick={clearCart}
              className={`text-sm transition-colors ${
                isDark ? 'text-gray-400 hover:text-red-500' : 'text-gray-500 hover:text-red-500'
              }`}
            >
              Clear Cart
            </button>
          </div>

          {/* Order Summary */}
          <div className={`lg:col-span-1`}>
            <div className={`sticky top-24 p-6 rounded-2xl ${
              isDark ? 'bg-dark-300' : 'bg-white shadow-lg'
            }`}>
              <h2 className={`text-xl font-bold mb-6 ${isDark ? 'text-white' : 'text-gray-900'}`}>
                Order Summary
              </h2>

              {/* Subtotal */}
              <div className={`flex justify-between mb-4 ${isDark ? 'text-gray-300' : 'text-gray-600'}`}>
                <span>Subtotal</span>
                <span>${cartTotal.toFixed(2)}</span>
              </div>

              {/* Tax */}
              <div className={`flex justify-between mb-4 ${isDark ? 'text-gray-300' : 'text-gray-600'}`}>
                <span>Tax (10%)</span>
                <span>${(cartTotal * 0.1).toFixed(2)}</span>
              </div>

              {/* Delivery */}
              <div className={`flex justify-between mb-6 ${isDark ? 'text-gray-300' : 'text-gray-600'}`}>
                <span>Delivery</span>
                <span className="text-green-500">Free</span>
              </div>

              {/* Divider */}
              <div className={`border-t ${isDark ? 'border-dark-400' : 'border-gray-200'} my-4`} />

              {/* Total */}
              <div className="flex justify-between mb-6">
                <span className={`font-bold text-lg ${isDark ? 'text-white' : 'text-gray-900'}`}>
                  Total
                </span>
                <span className="font-bold text-xl text-primary-500">
                  ${(cartTotal * 1.1).toFixed(2)}
                </span>
              </div>

              {/* Checkout Button */}
              <button
                onClick={handleCheckout}
                disabled={isCheckingOut}
                className={`w-full btn-primary flex items-center justify-center gap-2 ${
                  isCheckingOut ? 'opacity-70 cursor-not-allowed' : ''
                }`}
              >
                {isCheckingOut ? (
                  <>
                    <svg className="animate-spin w-5 h-5" fill="none" viewBox="0 0 24 24">
                      <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" />
                      <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z" />
                    </svg>
                    Processing...
                  </>
                ) : (
                  <>
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 9V7a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2m2 4h10a2 2 0 002-2v-6a2 2 0 00-2-2H9a2 2 0 00-2 2v6a2 2 0 002 2zm7-5a2 2 0 11-4 0 2 2 0 014 0z" />
                    </svg>
                    Proceed to Checkout
                  </>
                )}
              </button>

              {/* Continue Shopping */}
              <Link
                to="/menu"
                className={`block text-center mt-4 ${
                  isDark ? 'text-gray-400 hover:text-primary-400' : 'text-gray-600 hover:text-primary-500'
                }`}
              >
                Continue Shopping
              </Link>
            </div>
          </div>
        </div>
      </div>

      <style>{`
        @keyframes fadeIn {
          from { opacity: 0; transform: translateY(10px); }
          to { opacity: 1; transform: translateY(0); }
        }
      `}</style>
    </div>
  );
};

export default Cart;
